<template>
  <div class="webcamPLY">
    <div class="district_add p-0">
      <div id="app" class="web-camera-container">
        <div class="camera-button">
          <mdb-btn type="button" class="button is-rounded px-4 py-2" :class="{ 'is-primary' : !isCameraOpen, 'is-danger' : isCameraOpen}" @click="toggleCamera">
            <span style="font-size: 12px;" v-if="!isCameraOpen">Open Camera</span>
            <span style="font-size: 12px;" v-else>Close Camera</span>
          </mdb-btn>
        </div>

        <div class="d-flex w-100 justify-content-between">
          <div class="camera-select">
            <erpSelectAdd
              class="bg-white rounded"
              :options="deviceList"
              @select="selectDeviceLeft"
              :selected="device_name_left"
              label="Camera 1"
            />
          </div>
          <div class="camera-select">
            <erpSelectAdd
              class="bg-white rounded"
              :options="deviceList"
              @select="selectDeviceRight"
              :selected="device_name_right"
              label="Camera 2"
            />
          </div>
        </div>

        <div v-show="isCameraOpen && isLoading" class="camera-loading">
          <ul class="loader-circle">
            <li></li>
            <li></li>
            <li></li>
          </ul>
        </div>

        <div v-if="isCameraOpen" v-show="!isLoading" class="camera-box" :class="{ 'flash' : isShotPhoto }">
          <div class="camera-shutter" :class="{'flash' : isShotPhoto}"></div>

          <div class="camera-grid">
            <div class="camera-item">
              <video v-show="!isPhotoTaken" ref="cameraLeft" :width="600" :height="420" autoplay></video>
              <canvas v-show="isPhotoTaken" id="photoTakenLeft" ref="canvasLeft" :width="600" :height="420"></canvas>
            </div>
            <div class="camera-item">
              <video v-show="!isPhotoTaken" ref="cameraRight" :width="600" :height="420" autoplay></video>
              <canvas v-show="isPhotoTaken" id="photoTakenRight" ref="canvasRight" :width="600" :height="420"></canvas>
            </div>
          </div>
        </div>

        <div v-if="isCameraOpen && !isLoading" class="camera-shoot">
          <mdb-btn type="button" color="danger" @click="takePhoto" :disabled="!canTakePhoto" v-if="isPhotoTaken && isCameraOpen">
            <mdb-icon style="font-size: 25px;" icon="camera" />
          </mdb-btn>
          <mdb-btn type="button" color="success" @click="takePhoto" :disabled="!canTakePhoto" v-else>
            <mdb-icon style="font-size: 25px;" icon="camera" />
          </mdb-btn>
        </div>

        <div v-if="isPhotoTaken && isCameraOpen" class="camera-download bg-white">
          <a id="downloadPhoto" download="my-photo.jpg" style="font-size: 14px;" class="button bg-primary py-2 px-3 rounded text-white" role="button" @click="downloadImage">
            Download
          </a>
        </div>
      </div>

      <massage_box :hide="modal_status" :detail_info="modal_info"
      :m_text="$t('Failed_to_add')" @to_hide_modal="modal_status= false"/>

      <Toast ref="message"></Toast>
    </div>
  </div>
</template>

<script>
import erpSelectAdd from "../../components/erpSelect.vue";
import { mdbInput, mdbRow, mdbCol, mdbIcon, mdbBtn } from "mdbvue";
import { required } from 'vuelidate/lib/validators';

export default {
  name: "webcam_Add_double",
  data() {
    return {
      modal_info: '',
      modal_status: false,
      loading: false,
      isCameraOpen: false,
      isPhotoTaken: false,
      isShotPhoto: false,
      isLoading: false,
      deviceList: [],
      device_name_left: '',
      device_name_right: '',
      streamLeft: null,
      streamRight: null,
      isLeftReady: false,
      isRightReady: false
    };
  },
  components: {
    mdbInput, mdbRow, mdbCol, mdbIcon, mdbBtn, erpSelectAdd
  },
  validations: {
    name: { required }
  },
  computed: {
    canTakePhoto() {
      return this.isCameraOpen && !this.isLoading && this.isLeftReady && this.isRightReady;
    }
  },
  methods: {
    async selectDeviceLeft(option) {
      this.device_name_left = option.name;
      localStorage.device_left = option.id;
      await this.startStream(option.id, 'left');
    },
    async selectDeviceRight(option) {
      this.device_name_right = option.name;
      localStorage.device_right = option.id;
      await this.startStream(option.id, 'right');
    },
    funcAutoOpen() {
      this.isCameraOpen = true;
      this.createCameraElement();
    },
    toggleCamera() {
      if (this.isCameraOpen) {
        this.isCameraOpen = false;
        this.isPhotoTaken = false;
        this.isShotPhoto = false;
        this.isLeftReady = false;
        this.isRightReady = false;
        this.stopCameraStream();
      } else {
        this.isCameraOpen = true;
        this.createCameraElement();
      }
    },
    async ensureMediaDevices() {
      if (navigator.mediaDevices === undefined) {
        navigator.mediaDevices = {};
      }
      if (navigator.mediaDevices.getUserMedia === undefined) {
        navigator.mediaDevices.getUserMedia = function(constraints) {
          var getUserMedia = navigator.webkitGetUserMedia || navigator.mozGetUserMedia;
          if (!getUserMedia) {
            return Promise.reject(new Error('getUserMedia is not implemented in this browser'));
          }
          return new Promise(function(resolve, reject) {
            getUserMedia.call(navigator, constraints, resolve, reject);
          });
        };
      }
    },
    async createCameraElement() {
      this.isCameraOpen = true;
      this.deviceList = [];
      this.isLoading = true;
      await this.ensureMediaDevices();

      const devices = await navigator.mediaDevices.enumerateDevices();
      devices.forEach((device) => {
        if (device.kind === 'videoinput') {
          this.deviceList.push({
            id: device.deviceId,
            name: device.label || "Camera"
          });
        }
      });

      if (this.deviceList.length < 2) {
        this.$refs.message.warning('Second camera not found');
      }

      const leftDefault = localStorage.device_left || (this.deviceList[0] && this.deviceList[0].id);
      const rightDefault = localStorage.device_right || (this.deviceList[1] && this.deviceList[1].id) || leftDefault;

      const leftDevice = this.deviceList.find(item => item.id === leftDefault);
      const rightDevice = this.deviceList.find(item => item.id === rightDefault);

      this.device_name_left = leftDevice ? leftDevice.name : '';
      this.device_name_right = rightDevice ? rightDevice.name : '';

      try {
        await Promise.all([
          this.startStream(leftDefault, 'left'),
          this.startStream(rightDefault, 'right')
        ]);
        this.isLoading = false;
      } catch (error) {
        this.isLoading = false;
        alert("May the browser didn't support or there is some errors.");
      }
    },
    async startStream(deviceId, side) {
      if (!deviceId) {
        return;
      }
      if (side === 'left') {
        this.isLeftReady = false;
      } else {
        this.isRightReady = false;
      }
      const constraints = {
        audio: false,
        video: { facingMode: "user", deviceId: { exact: deviceId } }
      };
      const stream = await navigator.mediaDevices.getUserMedia(constraints);
      if (side === 'left') {
        this.stopStream(this.streamLeft);
        this.streamLeft = stream;
        const videoLeft = this.$refs.cameraLeft;
        if (videoLeft) {
          videoLeft.srcObject = stream;
          videoLeft.onloadedmetadata = () => {
            videoLeft.play();
            this.isLeftReady = true;
          };
        }
      } else {
        this.stopStream(this.streamRight);
        this.streamRight = stream;
        const videoRight = this.$refs.cameraRight;
        if (videoRight) {
          videoRight.srcObject = stream;
          videoRight.onloadedmetadata = () => {
            videoRight.play();
            this.isRightReady = true;
          };
        }
      }
    },
    stopStream(stream) {
      if (!stream) {
        return;
      }
      stream.getTracks().forEach(track => {
        track.stop();
      });
    },
    stopCameraStream() {
      this.stopStream(this.streamLeft);
      this.stopStream(this.streamRight);
      this.streamLeft = null;
      this.streamRight = null;
      this.isLeftReady = false;
      this.isRightReady = false;
    },
    takePhoto() {
      if (!this.canTakePhoto) {
        this.$refs.message.warning('Please wait for both cameras');
        return;
      }
      if (!this.isPhotoTaken) {
        this.isShotPhoto = true;
        const FLASH_TIMEOUT = 50;
        setTimeout(() => {
          this.isShotPhoto = false;
        }, FLASH_TIMEOUT);
      }

      this.isPhotoTaken = !this.isPhotoTaken;

      const contextLeft = this.$refs.canvasLeft.getContext('2d');
      contextLeft.drawImage(this.$refs.cameraLeft, 0, 0, 600, 420);

      const contextRight = this.$refs.canvasRight.getContext('2d');
      contextRight.drawImage(this.$refs.cameraRight, 0, 0, 600, 420);
    },
    async uploadImages(canvasLeft, canvasRight) {
      const requestOptions = {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          "image_base_64_1": canvasLeft,
          "image_base_64_2": canvasRight
        })
      };
      const response = await fetch(this.$store.state.hostname + "/TegirmonClient/getSaveBase64ImagesToFolderAndGetImageUrls", requestOptions);
      const data = await response.json();
      if (response.status === 201 || response.status === 200) {
        return { image_url: data.image_url_1, image_url_2: data.image_url_2 };
      }
      throw new Error('Upload failed');
    },
    async downloadImage() {
      const canvasLeft = document.getElementById("photoTakenLeft").toDataURL("image/jpeg");
      const canvasRight = document.getElementById("photoTakenRight").toDataURL("image/jpeg");

      try {
        const { image_url: leftUrl, image_url_2: rightUrl } = await this.uploadImages(canvasLeft, canvasRight);
        if (!leftUrl || !rightUrl) {
          this.$refs.message.warning('Both images are required');
          return false;
        }
        this.isCameraOpen = false;
        this.isPhotoTaken = false;
        this.isShotPhoto = false;
        this.stopCameraStream();
        this.$refs.message.success('Added_successfully');
        this.$emit('getPhotosub', { image_url: leftUrl, image_url_2: rightUrl });
        return true;
      } catch {
        this.loading = false;
        this.modal_info = this.$i18n.t('network_ne_connect');
        this.modal_status = true;
      }
    }
  }
};
</script>

